# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from flask import Flask, request
from prometheus_client import CollectorRegistry, generate_latest, Counter, multiprocess

app = Flask(__name__)

registry = CollectorRegistry()
multiprocess.MultiProcessCollector(registry)

request_counter = Counter(
    'http_requests_total', 
    'Total HTTP requests with user and path labels', 
    ['user_id', 'session_id', 'request_path'],
    registry=registry
)

@app.route('/metrics')
def metrics():
    return generate_latest(registry)

@app.before_request
def track_request():
    user_id = request.headers.get('X-User-Id', 'unknown')
    session_id = request.headers.get('X-Session-Id', 'unknown')
    request_path = request.path
    request_counter.labels(user_id, session_id, request_path).inc()

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)